/**
 * Career Pathways - Professional Career Categories and Jobs
 * Comprehensive career data for the Explore Careers section
 */

// Career categories for career exploration (separate from JobCategory for micro-jobs)
export type CareerCategory =
  | "HEALTHCARE_LIFE_SCIENCES"
  | "EDUCATION_TRAINING"
  | "TECHNOLOGY_IT"
  | "ARTIFICIAL_INTELLIGENCE"
  | "BUSINESS_MANAGEMENT"
  | "FINANCE_BANKING"
  | "SALES_MARKETING"
  | "MANUFACTURING_ENGINEERING"
  | "LOGISTICS_TRANSPORT"
  | "HOSPITALITY_TOURISM"
  | "TELECOMMUNICATIONS"
  | "CREATIVE_MEDIA"
  | "PUBLIC_SERVICE_SAFETY"
  | "MILITARY_DEFENCE"
  | "SPORT_FITNESS"
  | "REAL_ESTATE_PROPERTY"
  | "SOCIAL_CARE_COMMUNITY"
  | "CONSTRUCTION_TRADES";

export type WorkSetting = "hands-on" | "desk" | "outdoors" | "creative" | "mixed";
export type PeopleIntensity = "high" | "medium" | "low";

/** Careers with dedicated application paths where generic links
 *  (LinkedIn, utdanning.no, Samordna opptak, Coursera) are misleading. */
export type SpecialistPathType = "space" | "military" | "police" | "firefighter" | "elite-sport";

/**
 * How a young person actually gets into this career in Norway.
 *
 *   - "vocational"   — yrkesfag / fagbrev path. Vg1+Vg2 at 16-17, 2 years
 *                      apprenticeship, qualified at ~20. Hairdresser,
 *                      electrician, chef, beauty therapist, etc.
 *   - "university"   — academic path. Videregående (studieforberedende)
 *                      then bachelor's / master's / profesjonsstudium.
 *                      Doctor, nurse, psychologist, engineer, etc.
 *   - "mixed"        — several equally valid routes. E.g. optometrist
 *                      (bachelor's OR vocational); photographer (degree
 *                      OR self-taught). Generator defaults to university
 *                      but documents the vocational alternative.
 *   - "certification"— no academic degree; you qualify through professional
 *                      certifications / licences plus logged experience.
 *                      Scuba diving instructor, personal trainer, yoga
 *                      teacher, ski instructor, commercial pilot, etc. The
 *                      roadmap is a certification ladder, not a degree.
 *   - "on-the-job"   — no formal qualification expected at entry.
 *                      Shop assistant, delivery driver, etc.
 *
 * When absent, inferEducationRoute() falls back to scanning the
 * freeform educationPath string for keywords.
 */
export type EducationRoute =
  | "vocational"
  | "university"
  | "mixed"
  | "certification"
  | "on-the-job";

export interface Career {
  id: string;
  title: string;
  emoji: string;
  description: string;
  avgSalary: string;
  educationPath: string;
  /**
   * Structured override for which education route best matches this
   * career in Norway. Drives the roadmap generator's shape (vocational
   * careers start at Vg1, qualify via fagbrev around age 20, university
   * careers go via videregående → bachelor's, etc.). If absent, the
   * generator infers from educationPath text.
   */
  educationRoute?: EducationRoute;
  keySkills: string[];
  dailyTasks: string[];
  growthOutlook: "high" | "medium" | "stable";
  entryLevel?: boolean; // True if accessible without higher education
  // Optional explicit tags. If absent, the Career Radar falls back to
  // category defaults + per-id overrides (see WORK_SETTING_DEFAULTS etc.)
  workSetting?: WorkSetting;
  peopleIntensity?: PeopleIntensity;
  /** Specialist careers with dedicated application routes (ESA, Forsvaret, etc.) */
  pathType?: SpecialistPathType;
  /** Primary employment sector. If absent, derived from category defaults. */
  sector?: "public" | "private" | "mixed";
  /**
   * ISO timestamp of when avgSalary / growthOutlook were last verified
   * against an authoritative source (e.g. SSB wage stats, NAV outlook
   * report). Absent = never verified — the UI surfaces a "salary may
   * be out of date" disclaimer in that case. The runtime helper
   * `isCareerSalaryStale()` (see `lib/career-data-recency.ts`) treats
   * any career older than 12 months as stale.
   */
  lastVerifiedAt?: string;
  /** Public source URL backing the salary / growth figures. */
  sourceUrl?: string;
  /**
   * Finer-grained entry route for grade-aware ranking and the
   * `excludeUniversity` filter. Additive — absent = unknown, and the
   * existing `educationRoute` field keeps its 4-value contract for the
   * timeline generator. Populate opportunistically; unannotated careers
   * just skip the grade ranking and stay in their existing Match % sort.
   */
  entryRoute?: EntryRoute;
  /**
   * Typical grade band of successful applicants. Drives the "aligned
   * vs stretch" label in Career Radar once the user sets a gradeRange
   * preference. Never used to hide careers — see grade-match.ts.
   */
  gradeBand?: GradeBand;
  /**
   * ISO 3166-1 alpha-2 country code scoping a career that is genuinely
   * country-specific — most notably military careers, whose branches,
   * units, and entry routes differ per nation (e.g. Norway's Forsvaret:
   * Cyberforsvaret, Etterretningstjenesten, Marinejegerkommandoen).
   *
   * Absent = generic / not nation-specific (the default for the vast
   * majority of careers). Present = belongs to that country's structure
   * and should only be surfaced in that country's context once country
   * scoping is wired into the catalog. Additive and inert until then —
   * it never hides a career today, it just tags provenance so the
   * Norway-specific Forsvaret roles stay distinct from the generic
   * English-titled military archetypes.
   */
  country?: string;
}

/**
 * Infer the Norwegian education route a youth would take into a
 * career. Prefers the explicit `educationRoute` field when present;
 * otherwise scans the freeform `educationPath` string for signals.
 *
 * The generator uses the return value to pick the correct timeline
 * shape (vocational careers qualify at ~20 via fagbrev; university
 * careers graduate at ~22 via bachelor's; etc.).
 *
 * When signals conflict (e.g. "Bachelor's in Optometry OR vocational
 * training") the result is "mixed" — the generator still defaults to
 * the university shape but treats the vocational step as an
 * alternative worth surfacing.
 */
/**
 * Default education route for a whole category, used when a career's
 * `educationPath` text carries no degree/vocational keyword. Without this,
 * keyword-less careers (e.g. "Self-taught", "Youth academy → senior
 * contract", "Class B licence") fell through to a blanket "university"
 * default — which rendered a wrong, degree-shaped roadmap for trades,
 * creative, sport and hands-on careers.
 *
 * Only categories that genuinely lean away from a pure degree route are
 * listed. Predominantly degree-based categories (healthcare, education,
 * tech, finance, business, …) are intentionally absent so they keep the
 * "university" default — this map can only make a keyword-less career
 * *less* university-shaped, never wrongly downgrade a degree career.
 *
 * "mixed" means the timeline generator still defaults to the university
 * shape but surfaces the vocational alternative — a safe, strictly-more-
 * accurate result than hard "university".
 */
const CATEGORY_ROUTE_DEFAULTS: Partial<Record<CareerCategory, EducationRoute>> = {
  CONSTRUCTION_TRADES: "vocational",
  MANUFACTURING_ENGINEERING: "mixed",
  HOSPITALITY_TOURISM: "mixed",
  SPORT_FITNESS: "mixed",
  CREATIVE_MEDIA: "mixed",
  LOGISTICS_TRANSPORT: "mixed",
  SOCIAL_CARE_COMMUNITY: "mixed",
  PUBLIC_SERVICE_SAFETY: "mixed",
};

/**
 * The default education route for a category, or "university" when the
 * category is unknown or predominantly degree-based. Pure + side-effect
 * free so it can be unit-tested directly.
 */
export function categoryRouteDefault(
  category: CareerCategory | undefined,
): EducationRoute {
  return (category && CATEGORY_ROUTE_DEFAULTS[category]) || "university";
}

export function inferEducationRoute(career: Career): EducationRoute {
  if (career.educationRoute) return career.educationRoute;

  const path = career.educationPath.toLowerCase();

  const hasUniversity =
    /\b(bachelor|master|phd|doctorate|mba|degree|profesjonsstudium)\b/i.test(path);
  const hasVocational =
    /\b(vocational|fagbrev|apprenticeship|yrkesfag|l[æa]retid|fagskole|trade)\b/i.test(path);
  const hasCertification =
    /\b(certification|certificate|certified|licen[cs]e|licensed|PADI|SSI|instructor course|accreditation)\b/i.test(path);
  const hasOnTheJob = /\bon[- ]the[- ]job\b/i.test(path);

  if (hasUniversity && hasVocational) return "mixed";
  if (hasVocational) return "vocational";
  if (hasUniversity) return "university";
  // No degree, but a clear professional-certification/licence signal — a
  // certification ladder, not a degree (scuba instructor, PT, pilot, …).
  if (hasCertification) return "certification";
  if (hasOnTheJob) return "on-the-job";

  // No keyword signal in the freeform path — fall back to the category's
  // default route rather than blanket "university". This stops trades /
  // creative / hands-on careers from rendering a degree-shaped roadmap.
  // Predominantly degree-based categories aren't in the map, so they keep
  // the "university" default. The generator still respects the user's
  // current educationStage context.
  return categoryRouteDefault(getCategoryForCareer(career.id));
}

